        return -1;
    }

    if (em_len < 2*hLen+2 || db_len != em_len-1-hLen) {
        return -1;
    }

    /* Allocate */
    eq_mask = (uint8_t*) calloc(1, db_len);
    neq_mask = (uint8_t*) calloc(1, db_len);
    target_db = (uint8_t*) calloc(1, db_len);
    if (NULL == eq_mask || NULL == neq_mask || NULL == target_db) {
        result = -1;
        goto cleanup;
    }

