  EXPECT_EQ(clean_relative_path("../.."), fix_sep("../.."));
  EXPECT_EQ(clean_relative_path("../../abc"), fix_sep("../../abc"));
  // Remove leading slash
  EXPECT_EQ(clean_relative_path("/abc"), fix_sep("abc"));
  EXPECT_EQ(clean_relative_path("/"), fix_sep("."));
  // Remove trailing slash
