  EXPECT_EQ(clean_relative_path("../../"), fix_sep("../.."));
  EXPECT_EQ(clean_relative_path("/abc/"), fix_sep("abc"));
  // Remove doubled slash
  EXPECT_EQ(clean_relative_path("abc//def//ghi"), fix_sep("abc/def/ghi"));
  EXPECT_EQ(clean_relative_path("//abc"), fix_sep("abc"));
  EXPECT_EQ(clean_relative_path("///abc"), fix_sep("abc"));
  EXPECT_EQ(clean_relative_path("//abc//"), fix_sep("abc"));
  EXPECT_EQ(clean_relative_path("abc//"), fix_sep("abc"));
  // Remove . elements
